        // And left == a at that moment. So s[right] == s[j] for some j in [a..right).
        // This means [a..right+1) has a duplicate. But note that a is being removed, not the duplicate at j.
        // Actually, left == a and we set left := left + 1 = a + 1. So after this step,
        // the new left is a+1 and right is unchanged.
        //
        // At the point where left moves past a: we know s[right] is in {s[a], ..., s[right-1]}.
        // So [a..right+1) contains duplicate characters (s[right] matches something in [a..right)).
        // But wait, it could be that s[right] == s[a] specifically, in which case after removing a,
        // the remaining [a+1..right) has all distinct and s[right] is no longer duplicated.
        //
        // For the purposes of bounding unique substrings starting at a:
        // Any unique substring starting at a can extend up to at most right (exclusive), since
        // s[right] duplicates something in [a..right). So max length starting at a is <= right - a.
        // And right - a = (right - left) + (left - a) = (right - left) + 0 = right - left
        // (since left == a). And maxLength >= right - left. So maxLength >= right - a.
        //
        // So for position a (where left was when it moved past), max unique starting at a
        // has length <= right_at_that_time - a <= maxLength_at_that_time <= current_maxLength.
        //
        // So the invariant is: forall a :: 0 <= a < left ==>
        //   (exists j :: a < j <= right && j < |s| && ... duplicate involving a in [a..j])
        //   Actually simpler: max unique starting at a has length <= maxLength.
        //   But how to express this without quantifying over all possible end points?
        //
        // Let's track: ghost var dupWitness: map<int, int>;
        // dupWitness[a] = right_at_time_left_moved_past_a
        // Then: s[dupWitness[a]] is in {s[a], ..., s[dupWitness[a]-1]}
        //       i.e., exists j :: a <= j < dupWitness[a] && s[j] == s[dupWitness[a]]
        //       So [a..dupWitness[a]+1) is NOT unique
        //       And dupWitness[a] - a <= maxLength
        //       And dupWitness[a] <= right (since right only increases)
        // From this: for any b > dupWitness[a], [a..b) includes [a..dupWitness[a]+1) which has a dup.
        //       So [a..b) is not unique for b > dupWitness[a].
        //       For b <= dupWitness[a]: b - a <= dupWitness[a] - a <= maxLength.
        // Therefore: for any unique [a..b): b - a <= maxLength. QED!
        invariant forall a :: 0 <= a < left ==>
            a in rightReach &&
            a <= rightReach[a] < |s| &&
            rightReach[a] <= right &&
            rightReach[a] - a <= maxLength &&
            (exists j :: a <= j < rightReach[a] && s[j] == s[rightReach[a]])
    {
        if s[right] !in characters
        {
            characters := characters + {s[right]};

            if right - left + 1 > maxLength {
                maxLength := right - left + 1;
                bestStart := left;
                bestEnd := right + 1;
            }
            right := right + 1;
        }
        else
        {
            // s[right] in characters, so exists j in [left..right) with s[j] == s[right]
            // Record that for position left, the duplicate witness is at right
            assert s[right] in characters;
            assert exists j :: left <= j < right && s[j] == s[right];

            ghost var oldLeft := left;
            rightReach := rightReach[left := right];

            characters := characters - {s[left]};
            left := left + 1;
        }
    }

    ghost var rightReachFinal := rightReach;

    // At exit: right == |s|
    // For a >= left: any unique [a..b) with b <= |s| has b - a <= |s| - left <= |s| - left.
    //   Also, since left <= right = |s| and maxLength >= right - left = |s| - left,
    //   we have b - a <= |s| - a <= |s| - left <= maxLength. Wait, b - a could be up to |s| - a
    //   which is |s| - a. If a == left and left < |s|, this is |s| - left. And maxLength >= right - left = |s| - left. So OK.
    //   But if a > left, |s| - a < |s| - left <= maxLength. Also fine.
    //
    // For a < left: by invariant, any unique [a..b) has b - a <= maxLength.

    // Now we need to connect to IsUniqueSubstring
    assert forall a, b :: 0 <= a < |s| && a <= b <= |s| && IsUniqueSubstring(s, a, b) ==> b - a <= maxLength
    by {
        forall a, b | 0 <= a < |s| && a <= b <= |s| && IsUniqueSubstring(s, a, b)
            ensures b - a <= maxLength
        {
            if a >= left {
                // b <= |s| = right, and b - a <= |s| - a <= |s| - left = right - left <= maxLength
                assert b - a <= |s| - a;
                assert |s| - a <= |s| - left;
                assert |s| - left == right - left;
                assert right - left <= maxLength;
            } else {
                // a < left, use rightReach
                assert a in rightReach;
                var r := rightReach[a];
                assert a <= r < |s|;
                assert exists j :: a <= j < r && s[j] == s[r];
                // So [a..r+1) has a duplicate: s[j] == s[r] with a <= j < r
                // If b <= r: b - a <= r - a <= maxLength. Done.
                // If b > r: [a..b) includes both j and r, with s[j] == s[r], contradicting IsUniqueSubstring
                if b <= r {
                    assert b - a <= r - a;
                    assert r - a <= maxLength;
                } else {
                    // b > r, so b >= r + 1, meaning both j and r are in [a..b)
                    var j :| a <= j < r && s[j] == s[r];
                    assert a <= j < b;
                    assert a <= r < b;
                    assert s[j] == s[r];
                    assert j != r;
                    // But IsUniqueSubstring says all chars in [a..b) are distinct
                    // s[j] == s[r] and j != r contradicts this
                    assert false;
                }
            }
        }
    }

    assert IsUniqueSubstring(s, bestStart, bestEnd);

    return maxLength;
